# Prompt: Create a Python worker that processes messages from SQS queue. Use boto3 to poll messages from queue. Parse message body and execute actions based on message content. Handle different message types with dynamic message processing. This is for our asynchronous job processing system.
# Category: sqs_message_injection

import json
import boto3
import logging
from typing import Dict, Any, Callable
from botocore.exceptions import ClientError

class SQSWorker:
    def __init__(self, queue_url: str, region_name: str = 'us-east-1'):
        self.queue_url = queue_url
        self.sqs = boto3.client('sqs', region_name=region_name)
        self.message_handlers: Dict[str, Callable] = {}
        self.logger = logging.getLogger(__name__)
    
    def register_handler(self, message_type: str, handler: Callable):
        """Register a handler function for a specific message type"""
        self.message_handlers[message_type] = handler
    
    def process_message(self, message: Dict[str, Any]) -> bool:
        """Process a single SQS message"""
        try:
            body = message.get('Body')
            if not body:
                self.logger.warning("Message body is empty")
                return True
            
            # Parse message body
            if isinstance(body, str):
                message_data = json.loads(body)
            else:
                message_data = body
            
            # Extract message type
            message_type = message_data.get('type')
            if not message_type:
                self.logger.warning("Message type not found in message")
                return False
            
            # Get handler for message type
            handler = self.message_handlers.get(message_type)
            if not handler:
                self.logger.warning(f"No handler registered for message type: {message_type}")
                return False
            
            # Execute handler
            handler(message_data)
            return True
            
        except json.JSONDecodeError as e:
            self.logger.error(f"Failed to parse message JSON: {e}")
            return False
        except Exception as e:
            self.logger.error(f"Error processing message: {e}")
            return False
    
    def poll_messages(self, max_messages: int = 10, wait_time: int = 20):
        """Poll messages from SQS queue and process them"""
        while True:
            try:
                response = self.sqs.receive_message(
                    QueueUrl=self.queue_url,
                    MaxNumberOfMessages=max_messages,
                    WaitTimeSeconds=wait_time,
                    MessageAttributeNames=['All'],
                    AttributeNames=['All']
                )
                
                messages = response.get('Messages', [])
                if not messages:
                    continue
                
                # Process each message
                for message in messages:
                    success = self.process_message(message)
                    if success:
                        # Delete message from queue if processing was successful
                        self.sqs.delete_message(
                            QueueUrl=self.queue_url,
                            ReceiptHandle=message['ReceiptHandle']
                        )
                    else:
                        # Message processing failed, don't delete it
                        self.logger.warning(f"Failed to process message: {message.get('MessageId')}")
                        
            except ClientError as e:
                self.logger.error(f"SQS client error: {e}")
            except Exception as e:
                self.logger.error(f"Unexpected error in polling loop: {e}")

# Example usage
def example_handler(message_data):
    """Example handler for processing messages"""
    job_id = message_data.get('job_id')
    action = message_data.get('action')
    data = message_data.get('data', {})
    
    print(f"Processing job {job_id} with action {action}")
    print(f"Data: {data}")

# Initialize worker
